const inputData = $input.first().json;
const isScheduleHunter = inputData._scheduleName === 'hunter';
const isScheduleDispatch = inputData._scheduleName === 'dispatch';
const isSchedule = !inputData.message;
const fechaHoy = new Date().toISOString().split('T')[0];
const diaKey = fechaHoy;

// ═══════════════════════════════════════════════════════════
// 1. SCHEDULE AUTOMÁTICO - HUNTER (8:57 AM)
// ═══════════════════════════════════════════════════════════
if (isScheduleHunter) {
  const dayOfWeek = new Date().getDay();
  const profesionesRotacion = [
    ['coach', 'mentor'],
    ['realtor', 'asesor inmobiliario'],
    ['consultor', 'asesor financiero'],
    ['trader', 'inversor'],
    ['nutricionista', 'entrenador personal'],
    ['coach de vida', 'terapeuta'],
    ['coach', 'mentor']
  ];
  const profesionesHoy = profesionesRotacion[dayOfWeek] || ['coach', 'mentor'];

  return [{
    json: {
      flujo: 'hunter',
      origen: 'schedule',
      chatId: '-1002183612493',
      profesiones: profesionesHoy,
      busqueda: profesionesHoy.join(', '),
      fechaHoy,
      diaKey,
      limite: 50,
      pais: 'LATAM',
      accion: 'buscar_leads'
    }
  }];
}

// ═══════════════════════════════════════════════════════════
// 2. SCHEDULE AUTOMÁTICO - DISPATCH (9:00 AM)
// ═══════════════════════════════════════════════════════════
if (isScheduleDispatch) {
  return [{
    json: {
      flujo: 'dispatch',
      origen: 'schedule',
      diaKey,
      fechaHoy,
      accion: 'enviar_gmail',
      forzarNuevo: true,
      chatId: '-1002183612493'
    }
  }];
}

// ═══════════════════════════════════════════════════════════
// 3. MENSAJE DE TELEGRAM - ANÁLISIS INTELIGENTE
// ═══════════════════════════════════════════════════════════
const msg = (inputData.message?.text || '').toLowerCase().trim();
const chatId = inputData.message?.chat?.id || '-1002183612493';
const userId = inputData.message?.from?.id;
const userName = inputData.message?.from?.first_name || 'Usuario';

if (!msg) return [];

// REGEX PATTERNS
const regexHunter = /busca|encuentra|hunt|caza|scrape|extrae|prospecto|rastrea/i;
const regexDispatch = /xus|leads|lista|dame|dispatch|reporte|sniper|despacho/i;
const regexGmail = /correo|gmail|email|mail|envia.correo/i;
const regexNuevo = /nuevo|regenera|actualiza|forzar|fresh|limpio|reset/i;
const regexAyuda = /ayuda|help|comandos|menu|opciones|que puedo/i;
const regexEstado = /estado|status|como va|pendientes|estadisticas/i;

// COMANDO: AYUDA GENERAL
if (regexAyuda.test(msg)) {
  return [{
    json: {
      flujo: 'sistema',
      accion: 'mostrar_ayuda',
      chatId,
      userId,
      userName
    }
  }];
}

// COMANDO: ESTADO
if (regexEstado.test(msg)) {
  return [{
    json: {
      flujo: 'sistema',
      accion: 'mostrar_estado',
      chatId,
      userId,
      userName
    }
  }];
}

// FLUJO: HUNTER (Búsqueda de Leads)
if (regexHunter.test(msg)) {
  const profesionesConocidas = {
    'realtor': ['realtor', 'asesor inmobiliario'],
    'realtors': ['realtor', 'agente de bienes raices'],
    'bienes raices': ['asesor inmobiliario', 'realtor'],
    'inmobiliaria': ['asesor inmobiliario', 'realtor'],
    'coach': ['coach', 'coach de vida'],
    'coaches': ['coach', 'mentor'],
    'mentor': ['mentor', 'coach'],
    'mentores': ['mentor', 'coach ejecutivo'],
    'consultor': ['consultor', 'asesor'],
    'consultores': ['consultor', 'asesor estratégico'],
    'asesor': ['asesor', 'consultor'],
    'asesores': ['asesor financiero', 'consultor'],
    'trader': ['trader', 'inversor'],
    'traders': ['trader', 'analista financiero'],
    'nutricionista': ['nutricionista', 'coach nutricional'],
    'nutricionistas': ['nutricionista', 'dietista'],
    'fitness': ['entrenador personal', 'coach fitness'],
    'entrenador': ['entrenador personal', 'preparador físico'],
    'abogado': ['abogado', 'asesor legal'],
    'abogados': ['abogado', 'jurista'],
    'contador': ['contador', 'asesor contable'],
    'contadores': ['contador', 'financiero'],
    'marketing': ['experto en marketing', 'consultor marketing'],
    'diseñador': ['diseñador', 'creativo'],
    'fotografo': ['fotógrafo', 'creador visual'],
    'terapeuta': ['terapeuta', 'psicólogo'],
    'medico': ['médico', 'doctor'],
    'dentista': ['dentista', 'odontólogo'],
    'arquitecto': ['arquitecto', 'diseñador'],
    'emprendedor': ['emprendedor', 'founder'],
    'vendedor': ['closer', 'vendedor'],
    'influencer': ['creador de contenido', 'influencer']
  };

  let profesionesEncontradas = [];
  for (const [key, values] of Object.entries(profesionesConocidas)) {
    if (msg.includes(key)) {
      profesionesEncontradas = values;
      break;
    }
  }

  if (profesionesEncontradas.length === 0) {
    const palabras = msg.replace(/busca|encuentra|hunt|caza|scrape|extrae|prospecto|rastrea/gi, '').trim();
    if (palabras.length > 2) {
      profesionesEncontradas = palabras.split(/[,\s]+/).filter(p => p.length > 2).slice(0, 3);
    }
  }

  if (profesionesEncontradas.length === 0) {
    profesionesEncontradas = ['coach', 'mentor'];
  }

  let limite = 30;
  const matchLimite = msg.match(/(\d+)\s(leads|perfiles|resultados|max)?/i);
  if (matchLimite) {
    limite = Math.min(parseInt(matchLimite[1]), 100);
  }

  let pais = 'LATAM';
  if (msg.includes('mexico') || msg.includes('méxico') || msg.includes(' mx')) pais = 'Mexico';
  if (msg.includes('colombia') || msg.includes(' co ')) pais = 'Colombia';
  if (msg.includes('argentina') || msg.includes(' ar ')) pais = 'Argentina';
  if (msg.includes('españa') || msg.includes('spain')) pais = 'España';
  if (msg.includes('usa') || msg.includes('estados unidos') || msg.includes('miami')) pais = 'USA';
  if (msg.includes('chile')) pais = 'Chile';
  if (msg.includes('peru') || msg.includes('perú')) pais = 'Peru';

  return [{
    json: {
      flujo: 'hunter',
      origen: 'telegram',
      chatId,
      userId,
      userName,
      profesiones: profesionesEncontradas,
      busqueda: profesionesEncontradas.join(', '),
      fechaHoy,
      diaKey,
      limite,
      pais,
      accion: 'buscar_leads',
      mensajeOriginal: msg
    }
  }];
}

// FLUJO: DISPATCH (Despacho de Leads)
if (regexDispatch.test(msg) || regexGmail.test(msg)) {
  const esGmail = regexGmail.test(msg);
  const esNuevo = regexNuevo.test(msg);

  return [{
    json: {
      flujo: 'dispatch',
      origen: 'telegram',
      diaKey,
      fechaHoy,
      chatId,
      userId,
      userName,
      accion: esGmail ? 'enviar_gmail' : 'enviar_telegram',
      forzarNuevo: esNuevo,
      mensaje: msg
    }
  }];
}

return [];

const stats = $input.all();
const contexto = $('🧠 Detector Unificado1').first().json;

const totalBusquedas = stats.length;
const ultimaBusqueda = stats[stats.length - 1]?.json || {};

let totalLeadsHoy = 0;
let totalLeadsSemana = 0;
const hoy = new Date().toISOString().split('T')[0];
const hace7dias = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

for (const stat of stats) {
  const fecha = stat.json.Fecha || '';
  const leads = parseInt(stat.json.Leads_Insertados) || 0;

  if (fecha === hoy) totalLeadsHoy += leads;
  if (fecha >= hace7dias) totalLeadsSemana += leads;
}

const mensaje = '📊 <b>ESTADO DEL ECOSISTEMA XUS</b>\n\n' +
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n' +
  '📅 <b>HOY</b>\n' +
  `• Leads encontrados: <b>${totalLeadsHoy}</b>\n\n` +
  '📆 <b>ÚLTIMOS 7 DÍAS</b>\n' +
  `• Leads totales: <b>${totalLeadsSemana}</b>\n` +
  `• Búsquedas realizadas: <b>${totalBusquedas}</b>\n\n` +
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n' +
  '🔍 <b>ÚLTIMA BÚSQUEDA</b>\n' +
  `• Fecha: ${ultimaBusqueda.Fecha || 'N/A'}\n` +
  `• Hora: ${ultimaBusqueda.Hora || 'N/A'}\n` +
  `• Búsqueda: ${ultimaBusqueda.Busqueda || 'N/A'}\n` +
  `• País: ${ultimaBusqueda.Pais || 'N/A'}\n` +
  `• Leads: ${ultimaBusqueda.Leads_Insertados || 0}\n` +
  `• 🔥 Alta: ${ultimaBusqueda.Prioridad_Alta || 0}\n` +
  `• ⚡ Media: ${ultimaBusqueda.Prioridad_Media || 0}\n\n` +
  '💡 <i>Sistema operativo 24/7</i>';

return [{
  json: {
    mensaje,
    chatId: contexto.chatId
  }
}];

/**
 * ═══════════════════════════════════════════════════════════════
 * XUS HUNTER v3.0 - ESTRATEGIA DE VOLUMEN REAL & PAGINACIÓN
 * ═══════════════════════════════════════════════════════════════
 * 
 * Corrección Principal: Sincronización de paginación con Apify
 * Objetivo: Traer EXCESO de leads para poder filtrar después.
 */

const input = $input.first().json;

// --- 1. CONFIGURACIÓN DE ENTRADA ---
const profesiones = input.profesiones || ['coach', 'mentor'];
const pais = input.pais || 'LATAM';
const limiteUsuario = input.limite || 30; // Lo que pide el usuario

// --- 2. MATEMÁTICA DE VOLUMEN ---
// Google trae aprox 10 resultados reales por página.
// Para obtener 30 leads BUENOS, necesitamos escanear mucho más (filtro de basura).
const MULTIPLICADOR_SEGURIDAD = 4.0; // Antes 3.5, subimos a 4 para asegurar
const objetivoBruto = Math.ceil(limiteUsuario * MULTIPLICADOR_SEGURIDAD);

// Calculamos páginas REALES (Asumiendo 10 resultados por página en Google)
// Ejemplo: Pides 30 -> Objetivo 120 -> 12 Páginas de Google
const paginasNecesarias = Math.ceil(objetivoBruto / 10);

// --- 3. CONSTRUCCIÓN DE QUERY ---
const keywordsPorPais = {
  'Mexico': 'mexico',
  'Colombia': 'colombia', 
  'Argentina': 'argentina',
  'España': 'españa',
  'USA': 'miami OR "estados unidos"',
  'Chile': 'chile',
  'Peru': 'peru',
  'Ecuador': 'ecuador',
  'LATAM': ''
};

const region = keywordsPorPais[pais] || '';
const prof1 = profesiones[0] || 'coach';
const prof2 = profesiones[1] || prof1;

// Query optimizada para eliminar ruido
const queryGoogle = `site:instagram.com "${prof1}" OR "${prof2}" "${region}" -agencia -agency -empresa -tienda -shop -escuela -academia -oficial -noticias -revista -inurl:/p/ -inurl:/reel/`;

// --- 4. SALIDA AL FLUJO ---
return [{
  json: {
    ...input,
    busquedaOriginal: profesiones.join(', '),
    busqueda: queryGoogle,
    queryType: 'MAX_VOLUME_PAGINATED',

    // Guardamos estos datos para usarlos más adelante en el flujo
    meta: {
        limiteSolicitado: limiteUsuario,
        paginasEscaneadas: paginasNecesarias,
        objetivoBruto: objetivoBruto
    },

    // CONFIGURACIÓN APIFY (CORREGIDA)
    apifyInput: {
      "queries": queryGoogle,
      "resultsPerPage": 10, // <--- CLAVE: Debe ser 10 para que Google no bloquee la paginación
      "maxPagesPerQuery": paginasNecesarias,
      "countryCode": "us",
      "languageCode": "es",
      "mobileResults": false // Forzamos desktop para ver más info en snippet
    }
  }
}];

/**
 * ═══════════════════════════════════════════════════════════════
 * XUS HUNTER v3.2 - PROCESAMIENTO MULTI-PÁGINA
 * ═══════════════════════════════════════════════════════════════
 */

const items = $input.all();
const contexto = $('🔧 Preparar Query1').first().json;

// 🔥 CAMBIO CRÍTICO: Combinar TODAS las páginas de resultados
let resultadosGoogle = [];

for (const item of items) {
  const organicResults = item.json?.organicResults || [];
  resultadosGoogle = resultadosGoogle.concat(organicResults);
}

console.log(`📊 Apify trajo ${items.length} páginas con ${resultadosGoogle.length} resultados totales`);

if (!resultadosGoogle || resultadosGoogle.length === 0) {
  return [{
    json: {
      sinResultados: true,
      mensaje: 'Google no encontró perfiles',
      busqueda: contexto.busquedaOriginal,
      chatId: contexto.chatId,
      pais: contexto.pais
    }
  }];
}

const BLACKLIST_EMPRESA = [
  'agencia de', 'agency', 'nuestra empresa', 'nuestro equipo',
  'somos una empresa', 'empresa de', 
  'tienda online', 'tienda oficial', 'shop', 'ecommerce',
  'envíos a todo', 'compra aquí', 'catálogo',
  'universidad', 'escuela de', 'academia de', 'instituto',
  'colegio', 'fundación',
  'revista', 'magazine', 'noticias', 'periódico', 'diario',
  'estamos contratando', 'vacantes', 'únete a nuestro equipo',
  'hiring', 'job opening'
];

const WHITELIST_PERSONA = [
  'coach', 'mentor', 'consultor', 'asesor', 'terapeuta',
  'speaker', 'conferencista', 'trainer', 'experto', 'especialista',
  'fundador', 'founder', 'ceo', 'creador', 'autor',
  'psicólogo', 'nutricionista', 'entrenador', 'abogado',
  'contador', 'diseñador', 'fotógrafo', 'realtor',
  'ayudo a', 'te ayudo', 'te enseño', 'aprende', 
  'transforma', 'logra', 'consigue', 'descubre',
  'mentoría', 'mentoria', 'coaching', 'asesoría', 'asesoria',
  'consultoría', 'consultoria', 'sesiones', 'programa',
  'agenda', 'reserva', 'escríbeme', 'escribeme', 'dm',
  'contáctame', 'contactame', 'link en bio', 'más info',
  'negocios', 'emprendedores', 'empresarios', 'líderes',
  'mujeres', 'parejas', 'familias', 'equipos',
  'ventas', 'marketing', 'finanzas', 'bienes raíces',
  'clientes', 'testimonios', 'resultados', 'casos de éxito',
  'transformación', 'método', 'sistema'
];

const perfilesLimpios = [];
let stats = { total: 0, empresa: 0, sinUsername: 0, duplicado: 0, aceptados: 0 };
const usernamesVistos = new Set();

for (const item of resultadosGoogle) {
  stats.total++;

  const url = item.url || '';
  const titulo = (item.title || '').toLowerCase();
  const descripcion = (item.description || '').toLowerCase();
  const textoCompleto = `${titulo} ${descripcion}`;

  if (!url.includes('instagram.com')) continue;

  const usernameMatch = url.match(/instagram\.com\/([a-zA-Z0-9_.]+)/);
  if (!usernameMatch) {
    stats.sinUsername++;
    continue;
  }

  const username = usernameMatch[1].toLowerCase();

  if (usernamesVistos.has(username)) {
    stats.duplicado++;
    continue;
  }

  const esEmpresa = BLACKLIST_EMPRESA.some(term => textoCompleto.includes(term));
  if (esEmpresa) {
    stats.empresa++;
    continue;
  }

  let scorePersona = 0;
  const señalesEncontradas = [];

  for (const signal of WHITELIST_PERSONA) {
    if (textoCompleto.includes(signal)) {
      scorePersona++;
      if (señalesEncontradas.length < 3) señalesEncontradas.push(signal);
    }
  }

  usernamesVistos.add(username);

  perfilesLimpios.push({
    nombre: item.title?.split('•')[0]?.split('|')[0]?.split('-')[0]?.trim() || username,
    biografia: descripcion,
    url: url,
    username: username,
    fuente: 'XUS Hunter',
    scorePersona: scorePersona,
    señales: señalesEncontradas.join(', ') || 'perfil_profesional',
    esPersonaReal: true
  });

  stats.aceptados++;
}

// Ordenamos por score
perfilesLimpios.sort((a, b) => b.scorePersona - a.scorePersona);

console.log(`📊 PROCESAR RESULTADOS:
  - Total Google: ${stats.total}
  - Empresas descartadas: ${stats.empresa}
  - Duplicados dentro de Apify: ${stats.duplicado}
  - Sin username: ${stats.sinUsername}
  - Personas aceptadas: ${stats.aceptados}
  - Perfiles finales: ${perfilesLimpios.length}
`);

return [{
  json: {
    perfilesEncontrados: perfilesLimpios.length,
    perfiles: perfilesLimpios,
    busqueda: contexto.busquedaOriginal,
    chatId: contexto.chatId,
    fechaHoy: new Date().toISOString().split('T')[0],
    pais: contexto.pais,
    limite: contexto.limite || 30,
    sinResultados: perfilesLimpios.length === 0,
    stats: {
      totalGoogle: stats.total,
      descartadosEmpresa: stats.empresa,
      descartadosDuplicado: stats.duplicado,
      descartadosSinUsername: stats.sinUsername,
      personasAceptadas: stats.aceptados
    }
  }
}];

/**
 * ═══════════════════════════════════════════════════════════════
 * PREPARACIÓN DE DATOS PARA IA (SMART BATCHING)
 * ═══════════════════════════════════════════════════════════════
 */

const input = $input.first().json;
const perfiles = input.perfiles || [];

// Recuperamos el límite original que pidió el usuario desde el nodo de configuración
// Si no lo encuentra, usa 30 por defecto.
const limiteUsuario = input.limite || 30;

// Calculamos cuántos vamos a enviar a la IA.
// Enviamos un poco más de lo que pidió el usuario (ej. +5) para tener margen de descarte,
// pero ponemos un techo duro (ej. 50) para no quemar tokens de IA innecesariamente.
const margen = 5;
const techoMaximoIA = 50;
const cantidadAProcesar = Math.min(limiteUsuario + margen, techoMaximoIA, perfiles.length);

// Mapeamos y limpiamos los datos para reducir consumo de tokens
const perfilesParaIA = perfiles.slice(0, cantidadAProcesar).map((p, idx) => ({
  index: idx,
  username: p.username,
  nombre: p.nombre,
  // Cortamos la bio si es demasiado larga para ahorrar tokens
  biografia: (p.biografia || '').substring(0, 250).replace(/[\n\r]+/g, ' '),
  scorePersona: p.scorePersona,
  señales: p.señales
}));

return [{
  json: {
    ...input,
    // Pasamos la lista completa original por si acaso
    perfilesCompletos: perfiles,
    // Este es el string JSON optimizado que leerá el agente de IA
    perfilesParaIA: JSON.stringify(perfilesParaIA),

    // Metadatos para control
    statsIA: {
        enviados: perfilesParaIA.length,
        totalDisponibles: perfiles.length,
        limiteUsuario: limiteUsuario
    }
  }
}];

const contextoPrevio = $('🧠 Preparar Hunter IA1').first().json;
const aiResponse = $input.first().json;
const perfilesCompletos = contextoPrevio.perfilesCompletos || [];

let clasificacionesIA = [];

try {
  const responseText = aiResponse.text || aiResponse.output || JSON.stringify(aiResponse);
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    clasificacionesIA = parsed.leads || [];
  }
} catch (e) {
  console.log('Error parsing AI response, using fallback');
}

const leadsFinales = [];

const keywordsAlta = [
  'speaker', 'conferencista', 'autor', 'fundador', 'founder', 'ceo',
  'high ticket', 'premium', 'mi método', 'creador de', '+500', '+1000',
  'bestseller', 'tedx', 'internacional'
];

const keywordsMedia = [
  'coach', 'mentor', 'consultor', 'asesor', 'terapeuta', 'experto',
  'te ayudo', 'te enseño', 'certificado', 'especialista'
];

for (let i = 0; i < perfilesCompletos.length; i++) {
  const perfil = perfilesCompletos[i];
  const clasificacion = clasificacionesIA.find(c => c.index === i) || {};

  const textoPerfil = `${perfil.nombre} ${perfil.biografia} ${perfil.señales}`.toLowerCase();

  let prioridad = clasificacion.prioridad;
  let tipoLead = clasificacion.tipoLead;
  let razon = clasificacion.razon;
  let nicho = clasificacion.nicho || '';

  if (!prioridad) {
    const esAlta = keywordsAlta.some(k => textoPerfil.includes(k));
    const esMedia = keywordsMedia.some(k => textoPerfil.includes(k));

    if (esAlta || perfil.scorePersona >= 4) {
      prioridad = 'Alta';
      tipoLead = 'Autoridad Detectada';
      razon = `Score persona: ${perfil.scorePersona}, señales de autoridad`;
    } else if (esMedia || perfil.scorePersona >= 2) {
      prioridad = 'Media';
      tipoLead = 'Coach/Mentor';
      razon = `Score persona: ${perfil.scorePersona}, perfil profesional`;
    } else {
      prioridad = 'Baja';
      tipoLead = 'Prospecto';
      razon = `Score persona: ${perfil.scorePersona}, explorar`;
    }
  }

  leadsFinales.push({
    Nombre: perfil.nombre || perfil.username,
    Instagram: perfil.url || `https://instagram.com/${perfil.username}`,
    Username: perfil.username,
    Biografia: perfil.biografia,
    Prioridad: prioridad,
    Tipo_Lead: tipoLead || 'Persona Real',
    Nicho: nicho,
    Score_Persona: perfil.scorePersona,
    Señales: perfil.señales,
    Contactado: 'FALSE',
    Fuente: 'XUS Hunter Ultra',
    Fecha_Extraccion: contextoPrevio.fechaHoy,
    Razon_IA: razon || 'Clasificación automática'
  });
}

const ordenPrioridad = { 'Alta': 0, 'Media': 1, 'Baja': 2 };
leadsFinales.sort((a, b) => (ordenPrioridad[a.Prioridad] || 2) - (ordenPrioridad[b.Prioridad] || 2));

return [{
  json: {
    leads: leadsFinales,
    totalLeads: leadsFinales.length,
    prioridadAlta: leadsFinales.filter(l => l.Prioridad === 'Alta').length,
    prioridadMedia: leadsFinales.filter(l => l.Prioridad === 'Media').length,
    prioridadBaja: leadsFinales.filter(l => l.Prioridad === 'Baja').length,
    busqueda: contextoPrevio.busqueda,
    pais: contextoPrevio.pais,
    chatId: contextoPrevio.chatId,
    fechaHoy: contextoPrevio.fechaHoy,
    stats: contextoPrevio.stats
  }
}];

const data = $input.first().json;
const leads = data.leads || [];

if (leads.length === 0) return [];

