const aiResponse = $input.first().json;
const leadData = $('📦 Compilar Intel1').first().json;

let mensajes = {};
let parseSuccess = false;

try {
  const responseText = aiResponse.text || aiResponse.output || JSON.stringify(aiResponse);
  try {
    mensajes = JSON.parse(responseText.trim());
    parseSuccess = true;
  } catch (e1) {
    const jsonMatch = responseText.match(/\{[^{}]*"ruta"[^{}]*"b1"[^{}]*"b2"[^{}]*"b3"[^{}]*\}/);
    if (jsonMatch) {
      mensajes = JSON.parse(jsonMatch[0]);
      parseSuccess = true;
    } else {
      const flexMatch = responseText.match(/\{[\s\S]*?\}/);
      if (flexMatch) {
        mensajes = JSON.parse(flexMatch[0]);
        parseSuccess = true;
      }
    }
  }
} catch (e) {
  console.log('Parse failed:', e.message);
}

const primerNombre = leadData.primerNombre || 'Hola';
const ind = leadData._indicators || {};

let ruta = mensajes.ruta || null;
if (!ruta || !['A','B','C','D'].includes(ruta)) {
  if (ind.isHighTicket) ruta = 'B';
  else if (ind.isContentCreator && (ind.followers > 5000)) ruta = 'A';
  else if (ind.hasSystem) ruta = 'D';
  else ruta = 'C';
}

const fallbackSets = {
  A: [
    { b2: 'ese ritmo de contenido es serio... los DMs te deben estar matando, no?', b3: 'qué es lo que más tiempo te come del negocio hoy?' },
    { b2: 'publicar así de seguido no lo sostiene cualquiera', b3: 'y la parte operativa quién te la lleva o todo tú?' },
    { b2: 'con ese volumen de contenido me imagino que el día no te alcanza', b3: 'qué es lo que más te gustaría soltar si pudieras?' }
  ],
  B: [
    { b2: 'ese ticket con ese volumen de alumnos... me imagino que la carga es seria', b3: 'qué es lo que más te gustaría dejar de hacer tú mismo?' },
    { b2: 'facturar así está bien pero supongo que el día se va volando, no?', b3: 'qué parte te sigue cayendo a ti que preferirías no hacer?' },
    { b2: 'programa premium con esa cantidad de alumnos... eso pesa operativamente', b3: 'cuánto de eso todavía depende directamente de ti?' }
  ],
  C: [
    { b2: 'trabajo con negocios digitales y me dio curiosidad tu perfil', b3: 'en qué andas enfocado ahorita?' },
    { b2: 'me crucé con tu cuenta y me pareció interesante', b3: 'cuál es tu negocio principal?' },
    { b2: 'estuve viendo tu perfil y me surgió una pregunta genuina', b3: 'a qué te dedicas exactamente?' }
  ],
  D: [
    { b2: 'vi que tienes funnel y CRM armado... eso ya es más que la mayoría', b3: 'pero te están dando datos útiles o los tienes más de adorno?' },
    { b2: 'se nota que tienes cosas montadas, no improvisas', b3: 'sabes cuál de tus canales te trae los mejores clientes?' },
    { b2: 'tienes herramientas funcionando y eso no es común', b3: 'te dicen algo útil o nada más acumulan datos?' }
  ]
};

const fb = fallbackSets[ruta][Math.floor(Math.random() * fallbackSets[ruta].length)];

let b1 = mensajes.b1 || primerNombre;
if (b1.length < 2 || b1.length > 25) b1 = primerNombre;

let b2 = mensajes.b2 || fb.b2;
if (b2.split(' ').length > 20) b2 = fb.b2;

let b3 = mensajes.b3 || fb.b3;
if (b3.split(' ').length > 20) b3 = fb.b3;
if (!b3.endsWith('?')) b3 += '?';

// Detector de patrones IA
const iaPatterns = [
  /ya no es .+, es .+/i,
  /lo que define/i,
  /la pregunta es si/i,
  /te pone adelante del \d+/i,
  /el cuello de botella no es/i,
  /si tú paras/i,
  /no es lo mismo .+ que/i,
  /requiere estructura/i,
  /tiene un costo operativo/i,
  /eso te posiciona/i,
  /lo que separa a/i,
  /el verdadero reto/i,
  /la clave está en/i,
  /lo interesante es que/i,
  /sin duda/i,
  /definitivamente/i,
  /efectivamente/i
];

const soundsLikeAI = (text) => iaPatterns.some(p => p.test(text));

const spamPhrases = [
  'vi tu perfil', 'increíble', 'inspirador', 'inspiración',
  'me encanta tu', 'excelente trabajo', 'éxito', 'felicidades',
  'admiro', 'gran trabajo', 'maravilloso', 'te gustaría saber',
  'puedo ayudarte', 'tengo algo para ti'
];

const isSpammy = (text) => spamPhrases.some(p => text.toLowerCase().includes(p));

if (isSpammy(b2) || soundsLikeAI(b2)) b2 = fb.b2;
if (isSpammy(b3) || soundsLikeAI(b3)) b3 = fb.b3;

// Limpiar signos de apertura que la IA mete
b2 = b2.replace(/¿/g, '').replace(/¡/g, '').replace(/\.$/g, '').trim();
b3 = b3.replace(/¿/g, '').replace(/¡/g, '').trim();

return [{
  json: {
    ...leadData,
    _mensajes: {
      b1: b1.trim(),
      b2: b2,
      b3: b3
    },
    _ruta: ruta,
    _razonIA: mensajes.razon || 'Clasificación por indicadores',
    _parseSuccess: parseSuccess,
    _debug: {
      iaRaw: mensajes,
      fallbackUsed: !parseSuccess,
      iaDetected: soundsLikeAI(mensajes.b2 || '') || soundsLikeAI(mensajes.b3 || ''),
      timestamp: new Date().toISOString()
    }
  }
}];

