function unicodeToAscii(text) {
  if (!text) return '';

  const smallCapsMap = {
    'ᴀ':'A','ʙ':'B','ᴄ':'C','ᴅ':'D','ᴇ':'E','ꜰ':'F','ɢ':'G',
    'ʜ':'H','ɪ':'I','ᴊ':'J','ᴋ':'K','ʟ':'L','ᴍ':'M','ɴ':'N',
    'ᴏ':'O','ᴘ':'P','ꞯ':'Q','ʀ':'R','ꜱ':'S','ᴛ':'T','ᴜ':'U',
    'ᴠ':'V','ᴡ':'W','x':'X','ʏ':'Y','ᴢ':'Z',
    'ₐ':'a','ₑ':'e','ₒ':'o','ₓ':'x',
    'ᵃ':'a','ᵇ':'b','ᶜ':'c','ᵈ':'d','ᵉ':'e','ᶠ':'f','ᵍ':'g',
    'ʰ':'h','ⁱ':'i','ʲ':'j','ᵏ':'k','ˡ':'l','ᵐ':'m','ⁿ':'n',
    'ᵒ':'o','ᵖ':'p','ʳ':'r','ˢ':'s','ᵗ':'t','ᵘ':'u','ᵛ':'v',
    'ʷ':'w','ˣ':'x','ʸ':'y','ᶻ':'z',
