function isBlacklisted(word) {
  return BLACKLIST.includes(word.toLowerCase());
}

// ═══════════════════════════════════════════
// FUNCIÓN: Extraer nombre de persona
// ═══════════════════════════════════════════
function extraerNombrePersona(textoRaw) {
  if (!textoRaw || textoRaw.length < 2) return null;

  let texto = unicodeToAscii(textoRaw);
  const separadores = /[\|\-\–\—•✦★◆►▸⚡🔥💰🎯📈💎✨·\/\\]/;
  const partes = texto.split(separadores);

  for (const parte of partes) {
    let limpia = parte
      .replace(/[^\w\sáéíóúñüÁÉÍÓÚÑÜ']/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    if (limpia.length < 2) continue;

    const palabras = limpia.split(' ').filter(p => p.length > 1);
    if (palabras.length === 0 || palabras.length > 4) continue;

    for (const palabra of palabras) {
      const soloLetras = palabra.replace(/[áéíóúñüÁÉÍÓÚÑÜ]/g, 'a');
      if (/^[A-Za-z]{2,}$/.test(soloLetras) && !isBlacklisted(palabra)) {
        return palabra.charAt(0).toUpperCase() + palabra.slice(1).toLowerCase();
      }
    }
  }

  return null;
}

