const fuentes = {
  scrapedName: lead._scraped?.realName || '',
  nombreCompleto: lead.nombreCompleto || '',
  parsedName: lead.primerNombre || '',
  handle: lead._ig_handle || ''
};

let nombreFinal = null;
let fuenteUsada = 'generic';

nombreFinal = extraerNombrePersona(fuentes.scrapedName);
if (nombreFinal) fuenteUsada = 'scraped';

if (!nombreFinal) {
  nombreFinal = extraerNombrePersona(fuentes.nombreCompleto);
  if (nombreFinal) fuenteUsada = 'nombreCompleto';
}

if (!nombreFinal && fuentes.parsedName && fuentes.parsedName.length >= 3) {
  const limpio = unicodeToAscii(fuentes.parsedName);
  if (/^[a-záéíóúñü]+$/i.test(limpio) && limpio.length >= 3 && !isBlacklisted(limpio)) {
    nombreFinal = limpio.charAt(0).toUpperCase() + limpio.slice(1).toLowerCase();
    fuenteUsada = 'parsed';
  }
}

if (!nombreFinal && fuentes.handle) {
  const handleParts = fuentes.handle.split(/[._\-]/);
  for (const part of handleParts) {
    if (part && part.length >= 3 && part.length <= 14 && /^[a-zA-Z]+$/.test(part) && !isBlacklisted(part)) {
      nombreFinal = part.charAt(0).toUpperCase() + part.slice(1).toLowerCase();
      fuenteUsada = 'handle';
      break;
    }
  }
}

const esPersona = !!nombreFinal;
if (!nombreFinal) {
  nombreFinal = 'hola';
  fuenteUsada = 'generic';
}

